"use client";

import { motion, useReducedMotion } from "framer-motion";
import type { TimelineEvent } from "../../data/timeline";

interface Props {
  event: TimelineEvent;
  isActive: boolean;
  onExpand?: () => void;
}

export default function TimelineEventCard({ event, isActive, onExpand }: Props) {
  const reducedMotion = useReducedMotion();

  const variants = reducedMotion
    ? { active: { opacity: 1 }, inactive: { opacity: 0.4 } }
    : {
        active: { opacity: 1, y: 0, filter: "blur(0px)" },
        inactive: { opacity: 0.3, y: 12, filter: "blur(2px)" },
      };

  return (
    <motion.article
      className="flex-shrink-0 w-[85vw] md:w-[520px] lg:w-[560px] px-4 md:px-0"
      animate={isActive ? "active" : "inactive"}
      variants={variants}
      transition={{ duration: 0.5, ease: "easeOut" }}
      aria-current={isActive ? "step" : undefined}
    >
      <div className="space-y-5">
        {/* Meta row */}
        <div className="flex items-center gap-3">
          <span className="analytical-label text-accent">{event.category}</span>
          {event.milestone && (
            <span className="px-2 py-0.5 bg-accent/10 border border-accent/30 rounded text-[8px] font-mono text-accent uppercase tracking-widest">
              {event.milestone}
            </span>
          )}
          <span className="h-px flex-1 bg-white/10" />
          <span className="coordinate-label">
            {event.location ?? ""}
          </span>
        </div>

        {/* Date */}
        <p className="font-mono text-sm text-accent/70 tracking-widest">
          {event.start}
          {event.end ? ` — ${event.end}` : " — Present"}
        </p>

        {/* Title block */}
        <div>
          <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold tracking-tightest uppercase leading-none">
            {event.title}
          </h2>
          <p className="text-muted text-base md:text-lg mt-2 font-medium">
            {event.subtitle}
          </p>
        </div>

        {/* Quote */}
        {event.quote && isActive && (
          <motion.blockquote
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2, duration: 0.4 }}
            className="border-l-2 border-accent/30 pl-4 text-muted/60 italic text-sm leading-relaxed"
          >
            &ldquo;{event.quote}&rdquo;
          </motion.blockquote>
        )}

        {/* Summary */}
        <p className="text-muted/90 leading-relaxed text-sm md:text-base max-w-lg">
          {event.summary}
        </p>

        {/* Body preview */}
        {event.body && isActive && (
          <motion.p
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.15, duration: 0.35 }}
            className="text-muted/70 text-sm leading-relaxed max-w-lg border-l-2 border-accent/20 pl-4"
          >
            {event.body}
          </motion.p>
        )}

        {/* Achievements (first 3 when active) */}
        {event.achievements && event.achievements.length > 0 && isActive && (
          <ul className="space-y-2 pt-1">
            {event.achievements.slice(0, 3).map((a, i) => (
              <motion.li
                key={i}
                initial={{ opacity: 0, x: -8 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.1 + i * 0.06, duration: 0.3 }}
                className="flex items-start gap-3 text-sm text-muted/80"
              >
                <span className="mt-1.5 w-1.5 h-1.5 rounded-full bg-accent/50 flex-shrink-0" />
                {a}
              </motion.li>
            ))}
          </ul>
        )}

        {/* Tags */}
        {event.tags && event.tags.length > 0 && isActive && (
          <div className="flex flex-wrap gap-1.5 pt-1">
            {event.tags.map((tag) => (
              <span
                key={tag}
                className="px-2 py-0.5 rounded bg-white/5 border border-white/5 text-[9px] font-mono text-muted/40 uppercase tracking-widest"
              >
                {tag}
              </span>
            ))}
          </div>
        )}

        {/* Image thumbnails */}
        {event.media.length > 0 && (
          <div className="flex gap-2 pt-3 overflow-x-auto">
            {event.media.map((img) => (
              <figure key={img.id} className="flex-shrink-0">
                <div className="w-16 h-16 md:w-20 md:h-20 rounded-sm bg-background-layer2 border border-white/5 overflow-hidden">
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img
                    src={img.src}
                    alt={img.alt}
                    className="w-full h-full object-cover opacity-60"
                    loading="lazy"
                    style={img.position ? { objectPosition: img.position } : undefined}
                  />
                </div>
                {img.caption && isActive && (
                  <figcaption className="mt-1 text-[8px] text-muted/30 font-mono max-w-[80px] truncate">
                    {img.caption}
                  </figcaption>
                )}
              </figure>
            ))}
          </div>
        )}

        {/* Expand button — visible when active and has deeper content */}
        {isActive && (event.body || (event.achievements && event.achievements.length > 3) || event.links) && onExpand && (
          <button
            onClick={onExpand}
            className="btn-ghost text-xs flex items-center gap-2 mt-2 group"
          >
            <span>Read more</span>
            <svg
              width="12" height="12" viewBox="0 0 24 24" fill="none"
              stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
              className="group-hover:translate-x-0.5 transition-transform"
            >
              <path d="M5 12h14M12 5l7 7-7 7" />
            </svg>
          </button>
        )}
      </div>
    </motion.article>
  );
}
